import csv
import json
import collections
import re

def perform_data_quality_audit():
    """
    Performs a comprehensive data quality audit on the 'business.csv' dataset.
    Audits include missing values, anomalies in data types/formats, and row counts.
    Outputs the results as a JSON string.
    """

    DATA_FILE = './data_file'

    total_rows = 0
    headers = []

    # Audit metrics
    missing_values_count = collections.defaultdict(int)
    anomalies = {
        "value_non_numeric": 0,
        "value_negative": 0,
        "size_invalid_format": 0,
        "size_non_numeric_employees": 0,
        "unique_values_per_column": collections.defaultdict(set)
    }

    numeric_values_in_value_column = []

    try:
        with open(DATA_FILE, mode='r', encoding='utf-8') as f:
            # Read the first line to get raw headers and clean them
            reader = csv.reader(f)
            try:
                raw_headers = next(reader)
                headers = [h.strip() for h in raw_headers]
            except StopIteration:
                # File is empty or only contains headers, no data rows
                pass

            # Reset file pointer and use DictReader with cleaned headers
            f.seek(0) 
            dict_reader = csv.DictReader(f, fieldnames=headers)

            # Skip the actual header row if headers were successfully read
            if headers:
                try:
                    next(dict_reader) 
                except StopIteration:
                    # File only contained headers, no data rows
                    pass

            for row_data in dict_reader:
                total_rows += 1

                for key in headers: # Iterate through our cleaned headers to ensure all are processed
                    # Get value safely, handling cases where a row might have fewer columns than headers
                    value = row_data.get(key, "") 
                    cleaned_value = value.strip() if value is not None else ""

                    # Check for missing values
                    if not cleaned_value:
                        missing_values_count[key] += 1

                    # Store unique values for categorical columns and 'size'
                    if key in ['description', 'industry', 'level', 'line_code', 'size']:
                        anomalies["unique_values_per_column"][key].add(cleaned_value)

                    # Specific anomaly checks
                    if key == 'value':
                        if cleaned_value: # Only check if not missing
                            try:
                                val_int = int(cleaned_value)
                                numeric_values_in_value_column.append(val_int)
                                if val_int < 0:
                                    anomalies["value_negative"] += 1
                            except ValueError:
                                anomalies["value_non_numeric"] += 1

                    elif key == 'size':
                        if cleaned_value: # Only check if not missing
                            # Expected format: "X employees"
                            match = re.match(r'(\d+)\s*employees', cleaned_value)
                            if not match:
                                anomalies["size_invalid_format"] += 1
                            else:
                                try:
                                    # Try converting the extracted number to int
                                    int(match.group(1))
                                except ValueError:
                                    anomalies["size_non_numeric_employees"] += 1

    except FileNotFoundError:
        return json.dumps({
            "chartType": "none",
            "chartData": [],
            "chartConfig": {},
            "insight": f"Error: The file '{DATA_FILE}' was not found."
        })
    except Exception as e:
        return json.dumps({
            "chartType": "none",
            "chartData": [],
            "chartConfig": {},
            "insight": f"An error occurred during file processing: {str(e)}"
        })

    # --- Prepare Output ---

    # Missing values for chartData
    chart_data_missing = []
    for col, count in missing_values_count.items():
        if count > 0:
            chart_data_missing.append({"label": col, "value": count})

    # Sort by count descending for better visualization
    chart_data_missing.sort(key=lambda x: x["value"], reverse=True)

    # Insight generation
    insight_parts = [f"A comprehensive data quality audit was performed on {total_rows} rows."]

    # Missing Values Summary
    if total_rows > 0:
        total_missing_cells = sum(missing_values_count.values())
        if total_missing_cells > 0:
            insight_parts.append(f"\nMissing Values: A total of {total_missing_cells} missing values were identified across the dataset.")
            for col, count in missing_values_count.items():
                if count > 0:
                    insight_parts.append(f"- '{col}': {count} ({count/total_rows:.1%}) missing values.")
        else:
            insight_parts.append("\nMissing Values: No missing values were found in any column.")
    else:
        insight_parts.append("\nMissing Values: No data rows were processed, so no missing values could be identified.")


    # Anomalies Summary
    insight_parts.append("\nAnomalies Detected:")

    # Value column anomalies
    if anomalies["value_non_numeric"] > 0:
        insight_parts.append(f"- 'value' column: {anomalies['value_non_numeric']} entries are non-numeric and could not be converted to integers.")
    if anomalies["value_negative"] > 0:
        insight_parts.append(f"- 'value' column: {anomalies['value_negative']} numeric entries are negative, which might be unexpected depending on the data context.")

    if not anomalies["value_non_numeric"] and not anomalies["value_negative"]:
        insight_parts.append("- 'value' column: All entries are valid positive integers (or empty/missing).")

    # Min/Max for value column if numeric values exist
    if numeric_values_in_value_column:
        insight_parts.append(f"  Numeric 'value' range: Min={min(numeric_values_in_value_column)}, Max={max(numeric_values_in_value_column)}.")

    # Size column anomalies
    if anomalies["size_invalid_format"] > 0:
        insight_parts.append(f"- 'size' column: {anomalies['size_invalid_format']} entries do not follow the expected 'X employees' format.")
    if anomalies["size_non_numeric_employees"] > 0:
        insight_parts.append(f"- 'size' column: {anomalies['size_non_numeric_employees']} entries have an invalid (non-numeric) employee count within the 'X employees' format.")
    if not anomalies["size_invalid_format"] and not anomalies["size_non_numeric_employees"]:
        insight_parts.append("- 'size' column: All entries conform to the 'X employees' format with valid numeric employee counts (or empty/missing).")

    # Unique values for categorical columns
    insight_parts.append("\nUnique Values in Categorical Columns (for consistency check):")
    for col in ['description', 'industry', 'level', 'line_code', 'size']: # Include size to show unique formats
        if col in anomalies["unique_values_per_column"] and anomalies["unique_values_per_column"][col]:
            unique_vals = list(anomalies["unique_values_per_column"][col])
            if len(unique_vals) <= 5: # Show all if few
                insight_parts.append(f"- '{col}': {', '.join(sorted(unique_vals))}")
            else: # Show count and examples if many
                insight_parts.append(f"- '{col}': {len(unique_vals)} unique values (e.g., '{sorted(unique_vals)[0]}', '{sorted(unique_vals)[1]}', ...).")
        else:
            insight_parts.append(f"- '{col}': No unique values recorded (column might be entirely missing or empty).")


    final_insight = "\n".join(insight_parts)

    output = {
        "chartType": "bar" if chart_data_missing else "none",
        "chartData": chart_data_missing,
        "chartConfig": {
            "xKey": "label",
            "yKeys": ["value"],
            "xLabel": "Column Name",
            "yLabel": "Number of Missing Values"
        } if chart_data_missing else {},
        "insight": final_insight
    }

    return json.dumps(output, indent=2)

# Execute the function and print the result
print(perform_data_quality_audit())

